const birthday = Temporal.PlainDate
  .from('1995-12-25');

birthday.year;    // 1995
birthday.month;   // 12
birthday.day;     // 25

// No time zone. No midnight shift.
// December 25 everywhere.

const meeting = Temporal.ZonedDateTime
  .from({
    timeZone: 'America/New_York',
    year: 2026, month: 3, day: 22,
    hour: 14, minute: 30,
  });

// Convert to Tokyo:
meeting.withTimeZone('Asia/Tokyo');
// 2026-03-23T03:30:00+09:00[Asia/Tokyo]

const duration = Temporal.Duration
  .from({ months: 1, days: 3 });

const start = Temporal.PlainDate
  .from('2026-01-28');

start.add(duration);
// 2026-03-03 (handles Feb correctly)

const now = Temporal.Now.instant();

// Nanosecond precision
now.epochNanoseconds;
// 1742649600000000000n

// Compare two instants
Temporal.Instant.compare(a, b);
// -1, 0, or 1

const start = Temporal.PlainDate
  .from('2026-01-01');
const end = Temporal.PlainDate
  .from('2026-03-22');

start.until(end);
// P2M21D (2 months, 21 days)

start.until(end, {
  largestUnit: 'day'
});
// P81D (81 days)

const dates = [
  Temporal.PlainDate.from('2026-03-22'),
  Temporal.PlainDate.from('2025-12-01'),
  Temporal.PlainDate.from('2026-01-15'),
];

dates.sort(Temporal.PlainDate.compare);
// [2025-12-01, 2026-01-15, 2026-03-22]

// From ISO string
Temporal.PlainDate.from('2026-03-22');

// From object
Temporal.PlainDate.from({
  year: 2026, month: 3, day: 22
});

// Invalid dates throw (not silently wrong)
Temporal.PlainDate.from('2026-02-30');
// RangeError!
